#include <stdio.h>

int countRotations(int nums[], int n) {
    int left = 0, right = n - 1;
    while (left < right) {
        int mid = left + (right - left) / 2;
        if (nums[mid] > nums[right])
            left = mid + 1;
        else
            right = mid;
    }
    return left;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int nums[10000];
        for (int i = 0; i < n; ++i) scanf("%d", &nums[i]);
        printf("%d\n", countRotations(nums, n));
    }
    return 0;
}

